import{_ as t,o as s,c as i,a2 as o}from"./chunks/framework.BYlK8ftn.js";const p=JSON.parse('{"title":"0003 — Concurrent agent runs must isolate their git checkout","description":"","frontmatter":{},"headers":[],"relativePath":"decisions/0003-concurrent-run-checkout-isolation.md","filePath":"decisions/0003-concurrent-run-checkout-isolation.md","lastUpdated":1782023771000}'),a={name:"decisions/0003-concurrent-run-checkout-isolation.md"};function n(r,e,l,c,d,h){return s(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="_0003-—-concurrent-agent-runs-must-isolate-their-git-checkout" tabindex="-1">0003 — Concurrent agent runs must isolate their git checkout <a class="header-anchor" href="#_0003-—-concurrent-agent-runs-must-isolate-their-git-checkout" aria-label="Permalink to &quot;0003 — Concurrent agent runs must isolate their git checkout&quot;">​</a></h1><ul><li>Status: Accepted</li><li>Date: 2026-06-21</li><li>Deciders: Daedalus (CTO)</li><li>Context issue: <a href="https://github.com/Flopsstuff/korovany" target="_blank" rel="noreferrer">FLO-413</a></li></ul><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>This repo is worked by many concurrent agent runs that all share a single on-disk checkout at <code>/home/flop/projects/korovany</code>. A near-miss work-loss race was observed and filed by Iris (FLO-413):</p><ul><li>Two live runs of the same agent operated in the shared main checkout (their orchestration workspace was <code>null</code>, so they fell back to the shared tree instead of a per-run worktree).</li><li>The working tree mutated <strong>between commands</strong> of an inspecting run: <code>HEAD</code> advanced under it (<code>3cc1f7a</code> → <code>c15daa8</code>), a <code>git commit</code> returned &quot;nothing added to commit&quot; because a sibling had just committed identical content, and unrelated untracked files from other tickets appeared mid-session (<code>flo410-inventory-*.png</code>, <code>public/__crate_viewer.html</code>).</li></ul><p>The observed instance was harmless (the racing ops were no-ops). But the failure mode is real: a sibling mid-<code>git add</code> when another run commits, or two runs staging different files, can <strong>lose work, cross-contaminate commits, or push a diverged branch</strong>. At the time of filing the shared checkout sat on a feature branch <code>ahead 1, behind 1</code> of <code>main</code> with cross-ticket untracked files present — exactly the diverged state that precedes a bad push.</p><p>Decision lens: <em>trust the boundary</em> and <em>small-team discipline</em> — git&#39;s index is a single-writer resource; sharing it across concurrent writers violates that boundary, and the cost of a corrupted history far exceeds the cost of a worktree.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p><strong>Repo-level mitigation (in our control, effective now):</strong></p><p>Every agent run that stages or commits in this repo MUST do so in its own git worktree, never in the shared main checkout:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worktree</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ../korovany-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">slu</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">g</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin/main</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ln</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sfn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/flop/projects/korovany/node_modules</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ../korovany-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">slu</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">g</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/node_modules</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># work, commit, and push from ../korovany-&lt;slug&gt;</span></span></code></pre></div><p>This rule is now codified in <code>AGENTS.md</code> (Workflow) and <code>docs/guide/project-rules.md</code> (§3). It makes each run a single writer over its own index and working tree; only the push to <code>main</code> contends, and that is already serialized by the remote.</p><p><strong>Platform-level fix (out of our control — escalated):</strong></p><p>The root cause is orchestration: runs with a <code>null</code> execution workspace fall back to the shared checkout, and <code>transient_failure_retry</code> can spawn a retry while the prior run still holds the issue lock (the retry can then do nothing). The durable fix belongs to the Paperclip control plane (board-owned repo), not this repo. Recommended to the board:</p><ol><li>Give every run its own worktree by default — never default a <code>null</code>-workspace run into the shared main checkout; <strong>or</strong> serialize same-agent runs on a checkout.</li><li>Make <code>transient_failure_retry</code> either reap/transfer the prior run&#39;s lock to the retry, or not spawn a retry while the prior run is still <code>running</code>.</li></ol><p>Tracked as a child issue assigned to the CEO (board owns the <code>paperclip</code> repo).</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><ul><li><strong>Pro:</strong> removes index/worktree races between same-tree runs; aligns the written rules with what disciplined runs already do (most korovany work already happens in <code>korovany-floNNN</code> worktrees).</li><li><strong>Pro:</strong> a diverged/contaminated shared checkout no longer threatens a bad push, because no run commits there.</li><li><strong>Con:</strong> worktrees cost disk and a one-time <code>node_modules</code> symlink step; runs must remember to create one. Mitigated by making it a Golden-rule-adjacent hard rule in both rule files.</li><li><strong>Residual risk:</strong> the rule is advisory until the platform fix lands — a run that ignores it still races. The platform fix (above) is the real boundary; this ADR documents the interim contract.</li></ul>`,18)])])}const k=t(a,[["render",n]]);export{p as __pageData,k as default};
